#!/usr/bin/env python3\nimport paramiko\nimport time\n\nHOST = "168.119.79.238"\nPORT = 77\nUSERNAME = "sanliur"\nPASSWORD = "CHANGE_ME_CWP_SSH_PASSWORD"\n\ndef test_url(channel, url, name):\n    channel.send(f'curl -s -o /dev/null -w "{name}: %{{http_code}}\n" {url}\n')\n    time.sleep(2)\n\ndef main():\n    ssh = paramiko.SSHClient()\n    ssh.set_missing_host_key_policy(paramiko.AutoAddPolicy())\n    ssh.connect(HOST, port=PORT, username=USERNAME, password=PASSWORD, \n                timeout=20, look_for_keys=False, allow_agent=False)\n    \n    channel = ssh.invoke_shell()\n    time.sleep(2)\n    \n    print("=== DETAYLI SITE TESTLERI ===\n")\n    \n    base = "http://127.0.0.1:4321"\n    \n    tests = [\n        (f"{base}/", "Anasayfa"),\n        (f"{base}/admin", "Admin"),\n        (f"{base}/places", "Mekanlar"),\n        (f"{base}/blog", "Blog"),\n        (f"{base}/tarihi-yerler", "Tarihi Yerler"),\n        (f"{base}/etkinlikler", "Etkinlikler"),\n        (f"{base}/gastronomi", "Gastronomi"),\n        (f"{base}/giris", "Giris"),\n        (f"{base}/arama", "Arama"),\n        (f"{base}/hakkinda", "Hakkimizda"),\n        (f"{base}/api/health", "API Health"),\n    ]\n    \n    for url, name in tests:\n        test_url(channel, url, name)\n    \n    time.sleep(3)\n    \n    output = ""\n    while channel.recv_ready():\n        output += channel.recv(4096).decode('utf-8', errors='ignore')\n        time.sleep(1)\n    \n    print("TEST SONUCLARI:")\n    for line in output.split('\n')[-25:]:\n        if ':' in line and ('HTTP' in line or '200' in line or '301' in line or '302' in line or '404' in line or '500' in line):\n            print(line.strip()[:100])\n    \n    # Check PM2 status\n    channel.send("source ~/.nvm/nvm.sh && pm2 list | grep sanliurfa\n")\n    time.sleep(2)\n    \n    output2 = ""\n    while channel.recv_ready():\n        output2 += channel.recv(4096).decode('utf-8', errors='ignore')\n        time.sleep(0.5)\n    \n    print("\nPM2 STATUS:")\n    for line in output2.split('\n')[-5:]:\n        if 'sanliurfa' in line:\n            print(line.strip()[:150])\n    \n    channel.close()\n    ssh.close()\n\nif __name__ == "__main__":\n    main()\n
